#include "controller.h"

static bool controller_elapsed_ms(uint32_t now_ms, uint32_t since_ms)
{
    return (uint32_t) (now_ms - since_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static void controller_set_outputs(controller_t *controller, bool inlet_open, bool heater_on, controller_state_t state)
{
    controller->inlet_open = inlet_open;
    controller->heater_on = heater_on;
    controller->state = state;
}

static void controller_set_safe_idle(controller_t *controller)
{
    controller_set_outputs(controller, false, false, CONTROLLER_STATE_SAFE_IDLE);
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;
    bool force_safe_idle = false;
    bool temperature_rising = false;
    bool temperature_fresh;
    bool level_fresh;
    bool inlet_open = false;
    bool heater_on = false;
    controller_state_t state = CONTROLLER_STATE_SAFE_IDLE;
    const int previous_temperature_c = controller != 0 ? controller->last_temperature_c : 0;
    const bool had_valid_temperature = controller != 0 ? controller->has_valid_temperature : false;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        controller->has_valid_temperature = true;
        if (had_valid_temperature) {
            temperature_rising = controller->last_temperature_c > previous_temperature_c;
        }
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        controller->has_valid_level = true;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        force_safe_idle = true;
        output.timed_out = true;
        break;
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        force_safe_idle = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    temperature_fresh = controller->has_valid_temperature && !controller_elapsed_ms(input.now_ms, controller->last_temperature_ms);
    level_fresh = controller->has_valid_level && !controller_elapsed_ms(input.now_ms, controller->last_level_ms);
    if (!temperature_fresh || !level_fresh) {
        force_safe_idle = true;
        if (!temperature_fresh || !level_fresh) {
            output.timed_out = true;
        }
    }

    if (!force_safe_idle) {
        const bool low_level = controller->last_level < CONTROLLER_FILL_LEVEL_THRESHOLD;
        const bool safe_level = (controller->last_level >= CONTROLLER_FILL_LEVEL_THRESHOLD) &&
                                 (controller->last_level <= CONTROLLER_LEVEL_HIGH_THRESHOLD);
        const bool very_low_level = controller->last_level < CONTROLLER_MIN_HEATING_LEVEL;
        const bool temp_low = controller->last_temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD;
        const bool temp_hold = (controller->last_temperature_c >= CONTROLLER_TEMP_LOW_THRESHOLD) &&
                               (controller->last_temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD);
        const bool temp_early_off = (controller->last_temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) &&
                                    (controller->last_temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD);
        const bool temp_high = controller->last_temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD;

        if (low_level) {
            inlet_open = true;
            heater_on = false;
            state = CONTROLLER_STATE_FILLING;
        } else if (safe_level && temp_low) {
            inlet_open = false;
            heater_on = true;
            state = CONTROLLER_STATE_HEATING;
        } else if (safe_level && temp_hold) {
            inlet_open = false;
            heater_on = controller->heater_on;
            state = CONTROLLER_STATE_HOLDING;
        } else if (safe_level && temp_early_off) {
            inlet_open = false;
            heater_on = temperature_rising ? false : controller->heater_on;
            state = CONTROLLER_STATE_HOLDING;
        } else if (safe_level && temp_high) {
            inlet_open = false;
            heater_on = false;
            state = CONTROLLER_STATE_HOLDING;
        } else if (very_low_level) {
            inlet_open = true;
            heater_on = false;
            state = CONTROLLER_STATE_FILLING;
        } else {
            inlet_open = false;
            heater_on = false;
            state = CONTROLLER_STATE_HOLDING;
        }
    } else {
        controller_set_safe_idle(controller);
    }

    if (!force_safe_idle) {
        controller_set_outputs(controller, inlet_open, heater_on, state);
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
